create table rmais_boleto_workflow_errors (
    id            number,
    source        clob,
    msg           varchar2(1000 byte),
    created_by    varchar2(1000 byte),
    creation_date date
);

alter table rmais_boleto_workflow_errors
    add constraint rmais_boleto_workflow_errors_pk primary key ( id )
        using index enable;


